#include<cstdio>
#include<cstring>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;} 
const int N=1e6+10,M=2e6+10,INF=0x3f3f3f3f;
int head[N],des[M],nxt[M],cap[M],cgt=1,s,t,h2[N],cdt;
inline void ins(const int &x,const int &y,const int &z)
{
//	printf("real insert :: %d %d %d\n",x,y,z);
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
}
int dep[N],que[N],H,T;inline bool bfs()
{
	memset(dep,0,(cdt+2)<<2);dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
}
inline int dfs(const int &u=s,int in=INF)
{
	if(u==t)return in;int out=0;
	for(int &i=h2[u];i;i=nxt[i])if(cap[i]&&dep[des[i]]==dep[u]+1)
	{
		int tmp=dfs(des[i],min(in,cap[i]));
		cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
	}
	return out?out:dep[u]=0;
}
inline int dinic(){int res=0;while(bfs())memcpy(h2,head,(cdt+2)<<2),res+=dfs();return res;}
std::vector<int> S[55];int K[55],n,m,sm,h[55],idx[2][15];
int main()
{
//	FIN("P2754_2.in");
	n=read();m=read();sm=read();
	rep(1,m,i){h[i]=read();K[i]=read();rep(1,K[i],tt)S[i].push_back(read());}
	s=0;t=1;cdt=1;rep(1,n,i)idx[0][i]=++cdt;
	int T=0;while(true)
	{
		int I=(++T)&1;rep(1,n,i)ins(idx[I^1][i],idx[I][i]=++cdt,50);rep(1,m,i)
		{
			int u=S[i][(T-1+K[i])%K[i]],v=S[i][T%K[i]];//printf("ins %d --> %d :: %d\n",u,v,h[i]);
			if(u==-1)u=t;else u=idx[I^1][u];if(v==-1)v=t;else v=idx[I][v];ins(u,v,h[i]);
		}
		int tmp=dinic();if((sm-=tmp)<=0){printf("%d\n",T);return 0;}
		if(T>1000)return puts("0"),0;
	}
}
